import React from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const location = useLocation(); // Initialize the location hook
  const isLoggedIn = !!localStorage.getItem('token');

  if (location.pathname === '/') {
    return null;
  }

  return (
    <nav style={navStyle}>
      <div style={{ fontWeight: 'bold', fontSize: '1.5rem', color: '#1a1a1a' }}>
        📦 Vintage Vault
      </div>
      
      <div style={{ display: 'flex', gap: '25px', alignItems: 'center' }}>
        {isLoggedIn ? (
          <>
            <span onClick={() => navigate('/marketplace')} style={linkStyle}>
              Marketplace
            </span>
            <span onClick={() => navigate('/dashboard')} style={linkStyle}>
              Dashboard
            </span>
            <span onClick={() => { localStorage.clear(); navigate('/'); }} style={logoutButtonStyle}>
              Logout
            </span>
          </>
        ) : (
          <span onClick={() => navigate('/')} style={linkStyle}>
            Login
          </span>
        )}
      </div>
    </nav>
  );
};

// Pastel-inspired professional styles
const navStyle = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '15px 40px',
  backgroundColor: '#fdfcf0', // Soft pastel cream
  borderBottom: '1px solid #eee',
  position: 'sticky',
  top: 0,
  zIndex: 1000
};

const linkStyle = {
  textDecoration: 'none',
  color: '#444',
  fontWeight: '500',
  fontSize: '1rem'
};

const logoutButtonStyle = {
  padding: '8px 15px',
  backgroundColor: '#ffedea', // Soft pastel red/pink
  color: '#d32f2f',
  border: '1px solid #ffcdd2',
  borderRadius: '5px',
  cursor: 'pointer'
};

export default Navbar;
